// pubspec.yaml:
//   dependencies:
//     realm: ^3.6.0
//   dev_dependencies:
//     realm_generator: ^3.6.0
//     build_runner: ^2.4.13

// user.dart
import 'package:realm/realm.dart';
part 'user.realm.dart';

@RealmModel()
class _User {
  @PrimaryKey() late ObjectId id;
  late String email;
  late String name;

  @Indexed() late DateTime createdAt;

  late RealmList<_Order> orders;   // backing model class
}

@RealmModel()
class _Order {
  @PrimaryKey() late ObjectId id;
  late int totalCents;
  late DateTime createdAt;
}

// Run: dart run realm generate
// Produces User (public class), UserSchema, etc. from _User.

// ============ Open ============
import 'user.realm.dart';

final config = Configuration.local([User.schema, Order.schema]);
final realm = Realm(config);

// ============ Write ============
realm.write(() {
  final ada = User(ObjectId(), 'ada@x.com', 'Ada', DateTime.now());
  realm.add(ada);

  final order = Order(ObjectId(), 4299, DateTime.now());
  realm.add(order);
  ada.orders.add(order);
});

// ============ Query — RESULTS ARE LIVE ============
final activeUsers = realm.all<User>()
    .query('createdAt > \$0 SORT(createdAt DESC)', [DateTime(2026, 1, 1)]);

// LIVE: no re-fetch needed. Update any User → activeUsers.length + contents change.

// React to changes
final subscription = activeUsers.changes.listen((changes) {
  print('inserted: ${changes.inserted}');
  print('modified: ${changes.modified}');
  print('deleted:  ${changes.deleted}');
  print('now ${activeUsers.length} active users');
});

// ============ Widget consumption ============
// The idiomatic pattern: pass the RealmResults to a widget; it listens to changes.
StreamBuilder<RealmResultsChanges<User>>(
  stream: activeUsers.changes,
  builder: (ctx, snap) {
    return ListView.builder(
      itemCount: activeUsers.length,   // always current — live results
      itemBuilder: (_, i) => ListTile(title: Text(activeUsers[i].name)),
    );
  },
);

// ============ Update a live object ============
// Any reference stays in sync — after write, the reference IS the new state.
realm.write(() {
  ada.name = 'Ada Lovelace';
});
// Everyone holding `ada` immediately sees the new name. No cache invalidation.

// ============ Threading rules ============
// Realm objects are tied to their isolate. Cross-isolate: freeze first.
final frozen = ada.freeze();          // snapshot; safe to send to another isolate
await Isolate.run(() => processFrozen(frozen));

// Atlas Device Sync — data automatically syncs between phone, tablet, web, and
// MongoDB Atlas cloud with conflict resolution. Setup outline:

// 1. Create an App in MongoDB Atlas dashboard; enable Device Sync.
// 2. Configure schema in Atlas (matches your Realm models).
// 3. In Flutter:

final app = App(AppConfiguration('your-atlas-app-id'));
final user = await app.logIn(Credentials.emailPassword('u@x.com', 'password'));

// Flexible sync — client subscribes to a subset of data.
final config = Configuration.flexibleSync(user, [User.schema, Order.schema]);
final realm = Realm(config);

realm.subscriptions.update((subs) {
  subs.add(realm.all<User>(), name: 'all-users');
  subs.add(realm.query<Order>('owner == \$0', [user.id]), name: 'my-orders');
});
await realm.subscriptions.waitForSynchronization();

// Writes queue locally when offline; sync when reconnected.
realm.write(() {
  realm.add(Order(ObjectId(), 5000, DateTime.now()));
});

// Conflict resolution — Atlas uses 'last write wins' by default for scalar fields
// and CRDTs for lists/counters/collections. Custom logic possible via Atlas Functions.

// This eliminates a LOT of sync-engine work you'd otherwise write yourself.
// The trade-off is vendor lock-in and per-sync-user pricing.
